const fs = require('fs');
const path = require('path');

const promptPath = path.join(process.cwd(), 'prompts', 'fit_scorer.md');
let systemPrompt;
try {
  systemPrompt = fs.readFileSync(promptPath, 'utf-8');
} catch (e) {
  systemPrompt = `You are a precise job-fit scoring agent for Dev Rajput (MBA, 3+ years operations/client management). Score jobs 0-100 and return ONLY JSON with keys: score, verdict, top_matches, gaps, cv_variant, cover_letter_needed, rejection_reason. Thresholds: 75+ STRONG_MATCH, 60-74 GOOD_MATCH, below 60 REJECT.`;
}

const body = $input.first().json.body || $input.first().json;
const { job_title, company, location, description, source_platform, job_url } = body;

const userMessage = `Job Title: ${job_title}\nCompany: ${company}\nLocation: ${location}\n\nJob Description:\n${description}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    job_title,
    company,
    location,
    description,
    source_platform,
    job_url
  }
}];

const response = $input.first().json;
const text = (response.message && response.message.content) || response.response || '';

if (!text) throw new Error('Ollama returned empty response');

let scoreData;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON found');
  scoreData = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error(`Failed to parse score JSON: ${e.message}. Raw: ${text.substring(0, 300)}`);
}

const prev = $('Build Prompt').first().json;
scoreData.job_title = prev.job_title;
scoreData.company = prev.company;
scoreData.location = prev.location;
scoreData.description = prev.description;
scoreData.source_platform = prev.source_platform;
scoreData.job_url = prev.job_url;
scoreData.scored_at = new Date().toISOString();

return [{ json: scoreData }];
